import{_ as d,o as e,c as a,a3 as r}from"./chunks/framework.9hMwY-Rj.js";const m=JSON.parse('{"title":"Verification Sources — Free & Paid","description":"","frontmatter":{},"headers":[],"relativePath":"06_verification_sources.md","filePath":"06_verification_sources.md"}'),i={name:"06_verification_sources.md"};function o(n,t,s,l,c,h){return e(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="verification-sources-—-free-paid" tabindex="-1">Verification Sources — Free &amp; Paid <a class="header-anchor" href="#verification-sources-—-free-paid" aria-label="Permalink to &quot;Verification Sources — Free &amp; Paid&quot;">​</a></h1><p>ADLVS is source-agnostic: admins choose which provider verifies each data point, per campaign (see <a href="./03_key_features.html#admin-configuration">Admin Configuration</a>). This page catalogs the known options for each of the five data points — free and paid — beyond the primary/fallback pair already wired into the requirement spec.</p><blockquote><p>Pricing is indicative (USD, per the requirement document) and will drift — treat this as a shortlist to evaluate, not a locked-in bill of materials. If ADLVS procures a subscription on the client&#39;s behalf, add 10% administrative cost per the assumptions in the requirement doc.</p></blockquote><hr><h2 id="email-address" tabindex="-1">Email Address <a class="header-anchor" href="#email-address" aria-label="Permalink to &quot;Email Address&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Source</th><th>Type</th><th>Pricing</th><th>Notes</th></tr></thead><tbody><tr><td>Custom SMTP check (built-in)</td><td>Free</td><td>—</td><td>Default mechanism — confirms mailbox exists without sending mail</td></tr><tr><td>MX / DNS record lookup</td><td>Free</td><td>—</td><td>Confirms the domain can receive mail at all</td></tr><tr><td>Disposable-domain block list (open source)</td><td>Free</td><td>—</td><td>Flags throwaway/temp-mail addresses</td></tr><tr><td><strong>ZeroBounce</strong></td><td>Paid</td><td>$75 / 10k emails (PAYG)</td><td>Primary source — 10,000 credits</td></tr><tr><td><strong>NeverBounce</strong></td><td>Paid</td><td>~$80 / 10k (PAYG)</td><td>Fallback source — industry standard for &quot;sync&quot; cleaning workflows</td></tr><tr><td>Bouncer</td><td>Paid</td><td>~$60–80 / 10k (PAYG/Sub)</td><td>High accuracy, easy-to-use API</td></tr><tr><td>MyEmailVerifier</td><td>Paid</td><td>$25 / 10k (PAYG)</td><td>Extremely affordable — $0.0025/credit</td></tr><tr><td>MillionVerifier</td><td>Paid</td><td>~$6 / 10k (PAYG)</td><td>Best for high-volume, low-cost bulk cleaning</td></tr><tr><td>Emailable</td><td>Paid</td><td>~$30–50 / 10k (Sub/PAYG)</td><td>Modern UI, strong Zapier/API integrations</td></tr><tr><td>Verifalia</td><td>Paid</td><td>~$49 / 10k (Sub/PAYG)</td><td>Flexible plans, 25 free daily credits</td></tr><tr><td>Hunter.io</td><td>Paid</td><td>usage-based</td><td>Fallback source — also useful for email discovery</td></tr><tr><td>TowerData</td><td>Paid</td><td>usage-based</td><td>Fallback source</td></tr><tr><td>Deliverability Suite</td><td>Paid</td><td>~$49/month</td><td>Monitors domain reputation and ISP blocklisting</td></tr></tbody></table><hr><h2 id="phone-number" tabindex="-1">Phone Number <a class="header-anchor" href="#phone-number" aria-label="Permalink to &quot;Phone Number&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Source</th><th>Type</th><th>Pricing</th><th>Notes</th></tr></thead><tbody><tr><td>libphonenumber (Google, open source)</td><td>Free</td><td>—</td><td>Format/validity check only — no carrier or reachability data</td></tr><tr><td><strong>Twilio Lookup</strong></td><td>Paid</td><td>$0.01/request</td><td>Recommended entry point — carrier, line type</td></tr><tr><td>Numverify</td><td>Paid</td><td>Free tier (100 req/mo), then paid</td><td>Carrier, line type, location</td></tr><tr><td>AbstractAPI Phone Validation</td><td>Paid</td><td>Free tier + PAYG</td><td>Alternative to Numverify</td></tr><tr><td><strong>Vapi</strong></td><td>Paid</td><td>$0.05/minute</td><td>Primary AI voice bot — live reachability confirmation</td></tr><tr><td>Bland AI</td><td>Paid</td><td>usage-based</td><td>Alternative AI voice bot provider</td></tr></tbody></table><hr><h2 id="identity-job-title" tabindex="-1">Identity / Job Title <a class="header-anchor" href="#identity-job-title" aria-label="Permalink to &quot;Identity / Job Title&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Source</th><th>Type</th><th>Pricing</th><th>Notes</th></tr></thead><tbody><tr><td>Company website &quot;About / Team&quot; page</td><td>Free</td><td>—</td><td>Fallback source</td></tr><tr><td>Manual web/Google search</td><td>Free</td><td>—</td><td>Last-resort fallback when no other source matches</td></tr><tr><td>LinkedIn / Sales Navigator</td><td>Paid</td><td>Enterprise license</td><td>Primary source</td></tr><tr><td><strong>Apollo.io</strong></td><td>Paid</td><td>$49/month</td><td>Recommended entry cost</td></tr><tr><td>Clay</td><td>Paid</td><td>usage-based</td><td>Aggregates multiple identity sources into one lookup</td></tr><tr><td>ZoomInfo</td><td>Paid</td><td>Enterprise pricing</td><td>Deep B2B contact data</td></tr><tr><td>RocketReach</td><td>Paid</td><td>usage-based</td><td>Alternative contact/identity lookup</td></tr><tr><td>Lusha</td><td>Paid</td><td>usage-based</td><td>Alternative contact/identity lookup</td></tr></tbody></table><hr><h2 id="company" tabindex="-1">Company <a class="header-anchor" href="#company" aria-label="Permalink to &quot;Company&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Source</th><th>Type</th><th>Pricing</th><th>Notes</th></tr></thead><tbody><tr><td>Official company website</td><td>Free</td><td>—</td><td>Fallback source</td></tr><tr><td>OpenCorporates</td><td>Free (tier)</td><td>Paid API for scale</td><td>Public company registry lookup</td></tr><tr><td>Wikipedia / public filings</td><td>Free</td><td>—</td><td>Sanity check for large enterprises</td></tr><tr><td>LinkedIn Company Page / Insights</td><td>Paid</td><td>Enterprise license</td><td>Primary source</td></tr><tr><td>Glassdoor</td><td>Paid</td><td>scraped via Playwright</td><td>Company size / industry, fallback</td></tr><tr><td>Bloomberg</td><td>Paid</td><td>Enterprise license</td><td>Company size / industry, fallback</td></tr><tr><td><strong>Clearbit / Clay</strong></td><td>Paid</td><td>$0.15/company</td><td>Recommended entry cost</td></tr><tr><td>Crunchbase</td><td>Paid</td><td>usage-based</td><td>Alternative company data</td></tr></tbody></table><hr><h2 id="address" tabindex="-1">Address <a class="header-anchor" href="#address" aria-label="Permalink to &quot;Address&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Source</th><th>Type</th><th>Pricing</th><th>Notes</th></tr></thead><tbody><tr><td>OpenStreetMap Nominatim</td><td>Free</td><td>—</td><td>Free geocoding, lower accuracy on informal addresses</td></tr><tr><td>USPS Address Validation</td><td>Free</td><td>—</td><td>US addresses only</td></tr><tr><td><strong>Google Maps / Places API</strong></td><td>Paid</td><td>$0.002/request</td><td>Primary source — returns partial/exact match</td></tr><tr><td>SmartyStreets</td><td>Paid</td><td>usage-based</td><td>Alternative address validation</td></tr><tr><td>Loqate</td><td>Paid</td><td>usage-based</td><td>Strong international address coverage</td></tr><tr><td>Melissa Data</td><td>Paid</td><td>usage-based</td><td>Alternative address/identity data</td></tr></tbody></table><hr><h2 id="website-domain" tabindex="-1">Website / Domain <a class="header-anchor" href="#website-domain" aria-label="Permalink to &quot;Website / Domain&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Source</th><th>Type</th><th>Pricing</th><th>Notes</th></tr></thead><tbody><tr><td>DNS lookup (built-in)</td><td>Free</td><td>—</td><td>Confirms the domain resolves</td></tr><tr><td>WHOIS lookup</td><td>Free</td><td>—</td><td>Confirms domain registration details</td></tr><tr><td>URL validation (built-in)</td><td>Free</td><td>—</td><td>Confirms the page is reachable</td></tr><tr><td>WhoisXML API</td><td>Paid</td><td>usage-based</td><td>Bulk/automated WHOIS at scale</td></tr></tbody></table><hr><h2 id="how-this-maps-to-configuration" tabindex="-1">How This Maps to Configuration <a class="header-anchor" href="#how-this-maps-to-configuration" aria-label="Permalink to &quot;How This Maps to Configuration&quot;">​</a></h2><p>Every row marked <strong>bold</strong> above is the provider already named as primary in the <a href="./03_key_features.html#admin-configuration">Multi-Source Verification Engine</a> table. Everything else is an evaluated alternative or free fallback an admin can switch to per campaign — no code change required, per the &quot;Admin Configuration&quot; requirement (§2.1, §4 of the requirement doc).</p>',24)])])}const b=d(i,[["render",o]]);export{m as __pageData,b as default};
